   204→// RequestVerificationWithUser implements the Manager interface.
   205→func (p *UserPrivileges) RequestVerificationWithUser(db, table, column string, priv mysql.PrivilegeType, user *auth.UserIdentity) bool {
   206→	if SkipWithGrant {
   207→		return true
   208→	}
   209→	if user == nil {
   210→		return false
   211→	}
   212→	if user.Username == "" && user.Hostname == "" {
   213→		return true
   214→	}
   215→
   216→	// Skip check for INFORMATION_SCHEMA database.
   217→	// See https://dev.mysql.com/doc/refman/5.7/en/information-schema.html
   218→	if strings.EqualFold(db, "INFORMATION_SCHEMA") {
   219→		return true
   220→	}
   221→
   222→	terror.Log(p.Handle.ensureActiveUser(user.Username))
   223→	mysqlPriv := p.Handle.Get()
   224→	roles := mysqlPriv.getDefaultRoles(user.Username, user.Hostname)
   225→	return mysqlPriv.RequestVerification(roles, user.Username, user.Hostname, db, table, column, priv)
   226→}
