   228→func (p *UserPrivileges) authenticateWithPlugin(user *auth.UserIdentity, authentication, salt []byte, sessionVars *variable.SessionVars, authConn conn.AuthConn, authPlugin *extension.AuthPlugin, pwd string) error {
   229→	authRequest := extension.AuthenticateRequest{
   230→		User:             user.Username,
   231→		StoredAuthString: pwd,
   232→		InputAuthString:  authentication,
   233→		Salt:             salt,
   234→		ConnState:        sessionVars.TLSConnectionState,
   235→		AuthConn:         authConn,
   236→	}
   237→	if err := authPlugin.AuthenticateUser(authRequest); err != nil {
   238→		logutil.BgLogger().Warn("verify through extension auth plugin failed",
   239→			zap.String("plugin", authPlugin.Name), zap.String("username", user.Username), zap.Error(err))
   240→		hasPassword := "YES"
   241→		if len(authentication) == 0 {
   242→			hasPassword = "NO"
   243→		}
   244→		return ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   245→	}
   246→
   247→	// If the user is authenticated using extension auth plugin, populate the plugin request verification funcs
   248→	if authPlugin.VerifyPrivilege != nil {
   249→		p.authPluginRequestVerification = func(user, host string, activeRoles []*auth.RoleIdentity, db, table, column string, priv mysql.PrivilegeType) bool {
   250→			return authPlugin.VerifyPrivilege(extension.VerifyStaticPrivRequest{
   251→				User:        user,
   252→				Host:        host,
   253→				DB:          db,
   254→				Table:       table,
   255→				Column:      column,
   256→				StaticPriv:  priv,
   257→				ConnState:   sessionVars.TLSConnectionState,
   258→				ActiveRoles: activeRoles,
   259→			})
   260→		}
   261→	}
   262→	if authPlugin.VerifyDynamicPrivilege != nil {
   263→		p.authPluginRequestDynamicVerification = func(activeRoles []*auth.RoleIdentity, user, host, privName string, grantable bool) bool {
   264→			return authPlugin.VerifyDynamicPrivilege(extension.VerifyDynamicPrivRequest{
   265→				User:        user,
   266→				Host:        host,
   267→				DynamicPriv: privName,
   268→				ConnState:   sessionVars.TLSConnectionState,
   269→				ActiveRoles: activeRoles,
   270→				WithGrant:   grantable,
   271→			})
   272→		}
   273→	}
   274→	return nil
   275→}
