   316→// GetEncodedPassword implements the Manager interface.
   317→func (p *UserPrivileges) GetEncodedPassword(user, host string) string {
   318→	mysqlPriv := p.Handle.Get()
   319→	record := mysqlPriv.connectionVerification(user, host)
   320→	if record == nil {
   321→		logutil.BgLogger().Error("get user privilege record fail",
   322→			zap.String("user", user), zap.String("host", host))
   323→		return ""
   324→	}
   325→	if p.isValidHash(record) {
   326→		return record.AuthenticationString
   327→	}
   328→	return ""
   329→}
