   428→func checkAuthTokenClaims(claims map[string]any, record *UserRecord, tokenLife time.Duration) error {
   429→	if sub, ok := claims[jwtRepo.SubjectKey]; !ok {
   430→		return errors.New("lack 'sub'")
   431→	} else if sub != record.User {
   432→		return fmt.Errorf("Wrong 'sub': %s", sub)
   433→	}
   434→
   435→	if email, ok := claims[openid.EmailKey]; !ok {
   436→		return errors.New("lack 'email'")
   437→	} else if email != record.Email {
   438→		return fmt.Errorf("Wrong 'email': %s", email)
   439→	}
   440→
   441→	now := time.Now()
   442→	val, ok := claims[jwtRepo.IssuedAtKey]
   443→	if !ok {
   444→		return errors.New("lack 'iat'")
   445→	} else if iat, ok := val.(time.Time); !ok {
   446→		return fmt.Errorf("iat: %v is not a value of time.Time", val)
   447→	} else if now.After(iat.Add(tokenLife)) {
   448→		return errors.New("the token has been out of its life time")
   449→	} else if now.Before(iat) {
   450→		return errors.New("the token is issued at a future time")
   451→	}
   452→
   453→	if val, ok = claims[jwtRepo.ExpirationKey]; !ok {
   454→		return errors.New("lack 'exp'")
   455→	} else if exp, ok := val.(time.Time); !ok {
   456→		return fmt.Errorf("exp: %v is not a value of time.Time", val)
   457→	} else if now.After(exp) {
   458→		return errors.New("the token has been expired")
   459→	}
   460→
   461→	// `iss` is not required if `token_issuer` is empty in `mysql.user`
   462→	if iss, ok := claims[jwtRepo.IssuerKey]; ok && iss != record.AuthTokenIssuer {
   463→		return fmt.Errorf("Wrong 'iss': %s", iss)
   464→	} else if !ok && len(record.AuthTokenIssuer) > 0 {
   465→		return errors.New("lack 'iss'")
   466→	}
   467→
   468→	return nil
   469→}
