   471→// CheckPasswordExpired checks whether the password has been expired.
   472→func (*UserPrivileges) CheckPasswordExpired(sessionVars *variable.SessionVars, record *UserRecord) (bool, error) {
   473→	isSandBoxModeEnabled := variable.IsSandBoxModeEnabled.Load()
   474→	if record.PasswordExpired {
   475→		if isSandBoxModeEnabled {
   476→			return true, nil
   477→		}
   478→		return false, ErrMustChangePasswordLogin.GenWithStackByArgs()
   479→	}
   480→	if record.PasswordLifeTime != 0 {
   481→		lifeTime := record.PasswordLifeTime
   482→		if lifeTime == -1 {
   483→			pwdLifeTimeStr, err := sessionVars.GlobalVarsAccessor.GetGlobalSysVar(variable.DefaultPasswordLifetime)
   484→			if err != nil {
   485→				return false, err
   486→			}
   487→			lifeTime, err = strconv.ParseInt(pwdLifeTimeStr, 10, 64)
   488→			if err != nil {
   489→				return false, err
   490→			}
   491→		}
   492→		if lifeTime > 0 && record.PasswordLastChanged.AddDate(0, 0, int(lifeTime)).Before(time.Now()) {
   493→			if isSandBoxModeEnabled {
   494→				return true, nil
   495→			}
   496→			return false, ErrMustChangePasswordLogin.GenWithStackByArgs()
   497→		}
   498→	}
   499→	return false, nil
   500→}
