   506→		" Account is blocked for %s day(s) (%s day(s) remaining) due to %d "+
   507→		"consecutive failed logins.", user, host, lockTime,
   508→		remainTime, failedLoginAttempts))
   509→	return ErUserAccessDeniedForUserAccountBlockedByPasswordLock.FastGenByArgs(user, host,
   510→		lockTime, remainTime, failedLoginAttempts)
   511→}
