   513→// VerifyAccountAutoLockInMemory implements the Manager interface.
   514→func (p *UserPrivileges) VerifyAccountAutoLockInMemory(user string, host string) (bool, error) {
   515→	mysqlPriv := p.Handle.Get()
   516→	record := mysqlPriv.matchUser(user, host)
   517→	if record == nil {
   518→		logutil.BgLogger().Error("get authUser privilege record fail",
   519→			zap.String("authUser", user), zap.String("authHost", host))
   520→		return false, ErrAccessDenied.FastGenByArgs(user, host)
   521→	}
   522→
   523→	if record.AutoAccountLocked {
   524→		// If it is locked, need to check whether it can be automatically unlocked.
   525→		lockTime := record.PasswordLockTimeDays
   526→		if lockTime == -1 {
   527→			return record.AutoAccountLocked, GenerateAccountAutoLockErr(record.FailedLoginAttempts, user, host, "unlimited", "unlimited")
   528→		}
   529→		lastChanged := record.AutoLockedLastChanged
   530→		d := time.Now().Unix() - lastChanged
   531→		if d > lockTime*24*60*60 {
   532→			return record.AutoAccountLocked, nil
   533→		}
   534→		lds := strconv.FormatInt(lockTime, 10)
   535→		rds := strconv.FormatInt(int64(math.Ceil(float64(lockTime)-float64(d)/(24*60*60))), 10)
   536→		return record.AutoAccountLocked, GenerateAccountAutoLockErr(record.FailedLoginAttempts, user, host, lds, rds)
   537→	}
   538→	return record.AutoAccountLocked, nil
   539→}
