   541→// IsAccountAutoLockEnabled implements the Manager interface.
   542→func (p *UserPrivileges) IsAccountAutoLockEnabled(user string, host string) bool {
   543→	// If the service is started using skip-grant-tables, the system ignores whether
   544→	// to enable the automatic account locking feature after continuous login failure.
   545→	if SkipWithGrant {
   546→		p.user = user
   547→		p.host = host
   548→		return false
   549→	}
   550→	mysqlPriv := p.Handle.Get()
   551→	record := mysqlPriv.matchUser(user, host)
   552→	if record == nil {
   553→		return false
   554→	}
   555→	// For failed-login tracking and temporary locking to occur, an account's FAILED_LOGIN_ATTEMPTS
   556→	// and PASSWORD_LOCK_TIME options both must be nonzero.
   557→	// https://dev.mysql.com/doc/refman/8.0/en/create-user.html
   558→	if record.FailedLoginAttempts == 0 || record.PasswordLockTimeDays == 0 {
   559→		return false
   560→	}
   561→	return true
   562→}
