   587→// ConnectionVerification implements the Manager interface.
   588→func (p *UserPrivileges) ConnectionVerification(user *auth.UserIdentity, authUser, authHost string, authentication, salt []byte, sessionVars *variable.SessionVars, authConn conn.AuthConn) (info privilege.VerificationInfo, err error) {
   589→	if SkipWithGrant {
   590→		p.user = authUser
   591→		p.host = authHost
   592→		return
   593→	}
   594→
   595→	hasPassword := "YES"
   596→	if len(authentication) == 0 {
   597→		hasPassword = "NO"
   598→	}
   599→
   600→	mysqlPriv := p.Handle.Get()
   601→	record := mysqlPriv.connectionVerification(authUser, authHost)
   602→
   603→	if record == nil {
   604→		logutil.BgLogger().Error("get authUser privilege record fail",
   605→			zap.String("authUser", authUser), zap.String("authHost", authHost))
   606→		return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   607→	}
   608→
   609→	globalPriv := mysqlPriv.matchGlobalPriv(authUser, authHost)
   610→	if globalPriv != nil {
   611→		if !p.checkSSL(globalPriv, sessionVars.TLSConnectionState) {
   612→			logutil.BgLogger().Error("global priv check ssl fail",
   613→				zap.String("authUser", authUser), zap.String("authHost", authHost))
   614→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   615→		}
   616→	}
   617→
   618→	pwd := record.AuthenticationString
   619→	if !p.isValidHash(record) {
   620→		return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   621→	}
   622→
   623→	// If the user uses session token to log in, skip checking record.AuthPlugin.
   624→	if user.AuthPlugin == mysql.AuthTiDBSessionToken {
   625→		if err = sessionstates.ValidateSessionToken(authentication, user.Username); err != nil {
   626→			logutil.BgLogger().Warn("verify session token failed", zap.String("username", user.Username), zap.Error(err))
   627→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   628→		}
   629→	} else if record.AuthPlugin == mysql.AuthTiDBAuthToken {
   630→		if len(authentication) == 0 {
   631→			logutil.BgLogger().Error("empty authentication")
   632→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   633→		}
   634→		tokenString := string(hack.String(authentication[:len(authentication)-1]))
   635→		var (
   636→			claims map[string]any
   637→		)
   638→		if claims, err = GlobalJWKS.checkSigWithRetry(tokenString, 1); err != nil {
   639→			logutil.BgLogger().Error("verify JWT failed", zap.Error(err))
   640→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   641→		}
   642→		if err = checkAuthTokenClaims(claims, record, defaultTokenLife); err != nil {
   643→			logutil.BgLogger().Error("check claims failed", zap.Error(err))
   644→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   645→		}
   646→	} else if record.AuthPlugin == mysql.AuthLDAPSASL {
   647→		if err = ldap.LDAPSASLAuthImpl.AuthLDAPSASL(authUser, pwd, authentication, authConn); err != nil {
   648→			// though the pwd stores only `dn` for LDAP SASL, it could be unsafe to print it out.
   649→			// for example, someone may alter the auth plugin name but forgot to change the password...
   650→			logutil.BgLogger().Warn("verify through LDAP SASL failed", zap.String("username", user.Username), zap.Error(err))
   651→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   652→		}
   653→	} else if record.AuthPlugin == mysql.AuthLDAPSimple {
   654→		if err = ldap.LDAPSimpleAuthImpl.AuthLDAPSimple(authUser, pwd, authentication); err != nil {
   655→			logutil.BgLogger().Warn("verify through LDAP Simple failed", zap.String("username", user.Username), zap.Error(err))
   656→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   657→		}
   658→	} else if record.AuthPlugin == mysql.AuthSocket {
   659→		if string(authentication) != authUser && string(authentication) != pwd {
   660→			logutil.BgLogger().Error("Failed socket auth", zap.String("authUser", authUser),
   661→				zap.String("socket_user", string(authentication)),
   662→				zap.String("authentication_string", pwd))
   663→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   664→		}
   665→	} else if authPlugin, ok := p.authPlugins[record.AuthPlugin]; ok {
   666→		if err = p.authenticateWithPlugin(user, authentication, salt, sessionVars, authConn, authPlugin, pwd); err != nil {
   667→			return info, err
   668→		}
   669→	} else if len(pwd) > 0 && len(authentication) > 0 {
   670→		switch record.AuthPlugin {
   671→		// NOTE: If the checking of the clear-text password fails, please set `info.FailedDueToWrongPassword = true`.
   672→		case mysql.AuthNativePassword:
   673→			hpwd, err := auth.DecodePassword(pwd)
   674→			if err != nil {
   675→				logutil.BgLogger().Error("decode password string failed", zap.Error(err))
   676→				info.FailedDueToWrongPassword = true
   677→				return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   678→			}
   679→
   680→			if !auth.CheckScrambledPassword(salt, hpwd, authentication) {
   681→				info.FailedDueToWrongPassword = true
   682→				return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   683→			}
   684→		case mysql.AuthCachingSha2Password, mysql.AuthTiDBSM3Password:
   685→			authok, err := auth.CheckHashingPassword([]byte(pwd), string(authentication), record.AuthPlugin)
   686→			if err != nil {
   687→				logutil.BgLogger().Error("Failed to check caching_sha2_password", zap.Error(err))
   688→			}
   689→
   690→			if !authok {
   691→				info.FailedDueToWrongPassword = true
   692→				return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   693→			}
   694→		default:
   695→			logutil.BgLogger().Error("unknown authentication plugin", zap.String("authUser", authUser), zap.String("plugin", record.AuthPlugin))
   696→			return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   697→		}
   698→	} else if len(pwd) > 0 || len(authentication) > 0 {
   699→		info.FailedDueToWrongPassword = true
   700→		return info, ErrAccessDenied.FastGenByArgs(user.Username, user.Hostname, hasPassword)
   701→	}
   702→
   703→	// Login a locked account is not allowed.
   704→	locked := record.AccountLocked
   705→	if locked {
   706→		logutil.BgLogger().Error(fmt.Sprintf("Access denied for authUser '%s'@'%s'. Account is locked.", authUser, authHost))
   707→		return info, errAccountHasBeenLocked.FastGenByArgs(user.Username, user.Hostname)
   708→	}
   709→
   710→	// special handling to existing users or root user initialized with insecure
   711→	if record.ResourceGroup != "" {
   712→		info.ResourceGroupName = record.ResourceGroup
   713→	}
   714→	// Skip checking password expiration if the session is migrated from another session.
   715→	// Otherwise, the user cannot log in or execute statements after migration.
   716→	if user.AuthPlugin != mysql.AuthTiDBSessionToken {
   717→		info.InSandBoxMode, err = p.CheckPasswordExpired(sessionVars, record)
   718→	}
   719→	return
   720→}
