   878→// DBIsVisible implements the Manager interface.
   879→func (p *UserPrivileges) DBIsVisible(activeRoles []*auth.RoleIdentity, db string) bool {
   880→	if SkipWithGrant {
   881→		return true
   882→	}
   883→	// If SEM is enabled, respect hard rules about certain schemas being invisible
   884→	// Before checking if the user has permissions granted to them.
   885→	if sem.IsEnabled() && !p.RequestDynamicVerification(activeRoles, "RESTRICTED_TABLES_ADMIN", false) {
   886→		if sem.IsInvisibleSchema(db) {
   887→			return false
   888→		}
   889→	}
   890→	mysqlPriv := p.Handle.Get()
   891→	if mysqlPriv.DBIsVisible(p.user, p.host, db) {
   892→		return true
   893→	}
   894→	allRoles := mysqlPriv.FindAllUserEffectiveRoles(p.user, p.host, activeRoles)
   895→	for _, role := range allRoles {
   896→		if mysqlPriv.DBIsVisible(role.Username, role.Hostname, db) {
   897→			return true
   898→		}
   899→	}
   900→	return false
   901→}
